 17→/**
 18→ * Given a part and a face ID, compute a drawing plane sitting on that face.
 19→ * Face IDs: '+x', '-x', '+y', '-y', '+z', '-z'
 20→ */
 21→export function faceToDrawingPlane(part, faceId) {
 22→  const { position } = part;
 23→  const dims = getPartDimensions(part);
 24→
 25→  // Center of the part in domain coords
 26→  const cx = position.x + dims.width / 2;
 27→  const cy = position.y + dims.depth / 2;
 28→  const cz = position.z + dims.height / 2;
 29→
 30→  let origin, normal, up, uAxis, vAxis;
 31→
 32→  switch (faceId) {
 33→    case '+z': // top face
 34→      origin = { x: position.x, y: position.y, z: position.z + dims.height };
 35→      normal = { x: 0, y: 0, z: 1 };
 36→      uAxis = { x: 1, y: 0, z: 0 };
 37→      vAxis = { x: 0, y: 1, z: 0 };
 38→      up = { x: 0, y: 1, z: 0 };
 39→      break;
 40→    case '-z': // bottom face
 41→      origin = { x: position.x, y: position.y, z: position.z };
 42→      normal = { x: 0, y: 0, z: -1 };
 43→      uAxis = { x: 1, y: 0, z: 0 };
 44→      vAxis = { x: 0, y: 1, z: 0 };
 45→      up = { x: 0, y: 1, z: 0 };
 46→      break;
 47→    case '+x': // right face
 48→      origin = { x: position.x + dims.width, y: position.y, z: position.z };
 49→      normal = { x: 1, y: 0, z: 0 };
 50→      uAxis = { x: 0, y: 1, z: 0 };
 51→      vAxis = { x: 0, y: 0, z: 1 };
 52→      up = { x: 0, y: 0, z: 1 };
 53→      break;
 54→    case '-x': // left face
 55→      origin = { x: position.x, y: position.y, z: position.z };
 56→      normal = { x: -1, y: 0, z: 0 };
 57→      uAxis = { x: 0, y: 1, z: 0 };
 58→      vAxis = { x: 0, y: 0, z: 1 };
 59→      up = { x: 0, y: 0, z: 1 };
 60→      break;
 61→    case '+y': // back face
 62→      origin = { x: position.x, y: position.y + dims.depth, z: position.z };
 63→      normal = { x: 0, y: 1, z: 0 };
 64→      uAxis = { x: 1, y: 0, z: 0 };
 65→      vAxis = { x: 0, y: 0, z: 1 };
 66→      up = { x: 0, y: 0, z: 1 };
 67→      break;
 68→    case '-y': // front face
 69→      origin = { x: position.x, y: position.y, z: position.z };
 70→      normal = { x: 0, y: -1, z: 0 };
 71→      uAxis = { x: 1, y: 0, z: 0 };
 72→      vAxis = { x: 0, y: 0, z: 1 };
 73→      up = { x: 0, y: 0, z: 1 };
 74→      break;
 75→    default:
 76→      return { ...GROUND_PLANE };
 77→  }
 78→
 79→  return { origin, normal, up, uAxis, vAxis, sourcePartId: part.id, sourceFace: faceId };
 80→}
