  6→/**
  7→ * 3D select/move handler.
  8→ * Left-click to select, drag to move on a camera-perpendicular plane.
  9→ */
 10→export function createSelectHandler3d({ dispatch, editorDispatch, project, activeAssemblyId, snapEnabled, selectedId, selectedType }) {
 11→  const isEditMode = activeAssemblyId !== null;
 12→
 13→  return {
 14→    onPointerDown(intersection, e, toolState, viewport) {
 15→      if (e.button !== 0) return;
 16→
 17→      if (!intersection || !intersection.partId) {
 18→        // Clicked empty space - deselect and reset drawing plane
 19→        editorDispatch({ type: 'DESELECT' });
 20→        editorDispatch({ type: 'RESET_DRAWING_PLANE' });
 21→        return;
 22→      }
 23→
 24→      const { partId, objectId, point, faceNormal } = intersection;
 25→
 26→      // Determine face for drawing plane
 27→      if (faceNormal) {
 28→        const faceId = identifyFace(faceNormal);
 29→        const part = project.parts.find((p) => p.id === partId);
 30→        if (part) {
 31→          const plane = faceToDrawingPlane(part, faceId);
 32→          editorDispatch({ type: 'SET_DRAWING_PLANE', plane });
 33→        }
 34→      }
 35→
 36→      if (isEditMode) {
 37→        const part = project.parts.find((p) => p.id === partId && p.assemblyId === activeAssemblyId);
 38→        if (part) {
 39→          editorDispatch({ type: 'SELECT_OBJECT', id: part.id, objectType: 'part' });
 40→          editorDispatch({
 41→            type: 'UPDATE_TOOL_STATE',
 42→            payload: { dragging: true, startPoint: point, dragPartId: part.id },
 43→          });
 44→        } else {
 45→          editorDispatch({ type: 'DESELECT' });
 46→        }
 47→        return;
 48→      }
 49→
 50→      // Normal mode selection hierarchy: part -> assembly -> object
 51→      const part = project.parts.find((p) => p.id === partId);
 52→      if (!part) {
 53→        editorDispatch({ type: 'DESELECT' });
 54→        return;
 55→      }
 56→
 57→      const parametricObject = part.objectId
 58→        ? (project.objects || []).find((o) => o.id === part.objectId && o.editingPolicy === 'parametric')
 59→        : null;
 60→
 61→      if (parametricObject) {
 62→        editorDispatch({ type: 'SELECT_OBJECT', id: part.objectId, objectType: 'object' });
 63→        editorDispatch({
 64→          type: 'UPDATE_TOOL_STATE',
 65→          payload: { dragging: true, startPoint: point, dragObjectId: part.objectId },
 66→        });
 67→      } else if (part.assemblyId) {
 68→        editorDispatch({ type: 'SELECT_OBJECT', id: part.assemblyId, objectType: 'assembly' });
 69→        editorDispatch({
 70→          type: 'UPDATE_TOOL_STATE',
 71→          payload: { dragging: true, startPoint: point, dragAssemblyId: part.assemblyId },
 72→        });
 73→      } else {
 74→        editorDispatch({ type: 'SELECT_OBJECT', id: part.id, objectType: 'part' });
 75→        editorDispatch({
 76→          type: 'UPDATE_TOOL_STATE',
 77→          payload: { dragging: true, startPoint: point, dragPartId: part.id },
 78→        });
 79→      }
 80→    },
 81→
 82→    onPointerMove(intersection, e, toolState, viewport) {
 83→      if (!toolState.dragging || !toolState.startPoint) return;
 84→
 85→      // Get current 3D point on movement plane
 86→      const currentPoint = intersection?.planePoint;
 87→      if (!currentPoint) return;
 88→
 89→      const startPoint = toolState.startPoint;
 90→      let dx = currentPoint.x - startPoint.x;
 91→      let dy = currentPoint.z - startPoint.z; // Three.js Z = domain Y
 92→      let dz = -(currentPoint.y - startPoint.y); // Three.js Y = domain Z (negated for correct direction)
 93→
 94→      // Convert Three.js deltas to domain deltas
 95→      // Three.js: x=domain x, y=domain z, z=domain y
 96→      const domainDelta = {
 97→        dx: dx,
 98→        dy: dy,
 99→        dz: -dz, // correct back
100→      };
101→
102→      if (snapEnabled) {
103→        domainDelta.dx = snapToGrid(domainDelta.dx, SKETCH_GRID_MINOR);
104→        domainDelta.dy = snapToGrid(domainDelta.dy, SKETCH_GRID_MINOR);
105→        domainDelta.dz = snapToGrid(domainDelta.dz, SKETCH_GRID_MINOR);
106→        if (Math.abs(domainDelta.dx) < 1 && Math.abs(domainDelta.dy) < 1 && Math.abs(domainDelta.dz) < 1) return;
107→      }
108→
109→      if (toolState.dragObjectId) {
110→        dispatch({
111→          type: 'OBJECT_MOVE',
112→          objectId: toolState.dragObjectId,
113→          delta: domainDelta,
114→        });
115→      } else if (toolState.dragAssemblyId) {
116→        dispatch({
117→          type: 'ASSEMBLY_MOVE',
118→          assemblyId: toolState.dragAssemblyId,
119→          delta: domainDelta,
120→        });
121→      } else if (toolState.dragPartId) {
122→        const part = project.parts.find((p) => p.id === toolState.dragPartId);
123→        if (!part || part.type === 'dimension') return;
124→
125→        const pos = {
126→          x: part.position.x + domainDelta.dx,
127→          y: part.position.y + domainDelta.dy,
128→          z: part.position.z + domainDelta.dz,
129→        };
130→
131→        if (snapEnabled) {
132→          pos.x = snapToGrid(pos.x, SKETCH_GRID_MINOR);
133→          pos.y = snapToGrid(pos.y, SKETCH_GRID_MINOR);
134→          pos.z = snapToGrid(pos.z, SKETCH_GRID_MINOR);
135→        }
136→
137→        dispatch({
138→          type: 'PART_UPDATE',
139→          part: { id: toolState.dragPartId, position: pos },
140→        });
141→      }
142→
143→      editorDispatch({
144→        type: 'UPDATE_TOOL_STATE',
145→        payload: { startPoint: currentPoint },
146→      });
147→    },
148→
149→    onPointerUp(intersection, e, toolState) {
150→      if (toolState.dragging) {
151→        editorDispatch({
152→          type: 'UPDATE_TOOL_STATE',
153→          payload: {
154→            dragging: false,
155→            startPoint: null,
156→            dragPartId: null,
157→            dragAssemblyId: null,
158→            dragObjectId: null,
159→          },
160→        });
161→      }
162→    },
163→
164→    onDoubleClick(intersection, e, toolState) {
165→      if (isEditMode) return;
166→      if (!intersection?.partId) return;
167→
168→      const part = project.parts.find((p) => p.id === intersection.partId);
169→      if (!part || !part.assemblyId) return;
170→
171→      const parametricObject = part.objectId
172→        ? (project.objects || []).find((o) => o.id === part.objectId && o.editingPolicy === 'parametric')
173→        : null;
174→      if (parametricObject) return;
175→
176→      editorDispatch({ type: 'ENTER_ASSEMBLY_EDIT', assemblyId: part.assemblyId });
177→    },
178→
179→    onKeyDown(e, toolState, currentSelectedId) {
180→      if (e.key === 'Escape' && isEditMode) {
181→        e.preventDefault();
182→        e.stopPropagation();
183→        editorDispatch({ type: 'SET_ACTIVE_ASSEMBLY', assemblyId: null });
184→        return;
185→      }
186→
187→      if ((e.key === 'Delete' || e.key === 'Backspace') && currentSelectedId) {
188→        if (selectedType === 'object') {
189→          dispatch({ type: 'OBJECT_DELETE', objectId: currentSelectedId });
190→        } else if (selectedType === 'assembly' && !isEditMode) {
191→          dispatch({ type: 'ASSEMBLY_DELETE_WITH_PARTS', assemblyId: currentSelectedId });
192→        } else {
193→          dispatch({ type: 'PART_DELETE', partId: currentSelectedId });
194→        }
195→        editorDispatch({ type: 'DESELECT' });
196→      }
197→    },
198→
199→    getCursor(toolState) {
200→      if (toolState?.dragging) return 'grabbing';
201→      return 'default';
202→    },
203→  };
204→}
