  1→import * as THREE from 'three';
  2→import { GROUND_PLANE } from '../domain/drawingPlane';
  3→
  4→const GRID_COLOR = 0xB8860B;
  5→const GRID_OPACITY = 0.12;
  6→const PREVIEW_COLOR = 0xB8860B;
  7→const PREVIEW_OPACITY = 0.3;
  8→
  9→/**
 10→ * Three.js Group that renders:
 11→ * 1) A translucent grid on the active drawing plane
 12→ * 2) A rectangle preview during draw operations
 13→ */
 14→export function createDrawingPlaneOverlay() {
 15→  const group = new THREE.Group();
 16→  group.name = 'DrawingPlaneOverlay';
 17→
 18→  let gridMesh = null;
 19→  let previewMesh = null;
 20→
 21→  const gridMaterial = new THREE.MeshBasicMaterial({
 22→    color: GRID_COLOR,
 23→    transparent: true,
 24→    opacity: GRID_OPACITY,
 25→    side: THREE.DoubleSide,
 26→    depthWrite: false,
 27→  });
 28→
 29→  const gridLineMaterial = new THREE.LineBasicMaterial({
 30→    color: GRID_COLOR,
 31→    transparent: true,
 32→    opacity: 0.2,
 33→  });
 34→
 35→  const previewMaterial = new THREE.MeshBasicMaterial({
 36→    color: PREVIEW_COLOR,
 37→    transparent: true,
 38→    opacity: PREVIEW_OPACITY,
 39→    side: THREE.DoubleSide,
 40→    depthWrite: false,
 41→  });
 42→
 43→  const previewEdgeMaterial = new THREE.LineBasicMaterial({
 44→    color: PREVIEW_COLOR,
 45→    transparent: true,
 46→    opacity: 0.8,
 47→  });
 48→
 49→  function clearGrid() {
 50→    if (gridMesh) {
 51→      group.remove(gridMesh);
 52→      gridMesh.traverse((child) => {
 53→        if (child.geometry) child.geometry.dispose();
 54→      });
 55→      gridMesh = null;
 56→    }
 57→  }
 58→
 59→  function clearPreview() {
 60→    if (previewMesh) {
 61→      group.remove(previewMesh);
 62→      previewMesh.traverse((child) => {
 63→        if (child.geometry) child.geometry.dispose();
 64→      });
 65→      previewMesh = null;
 66→    }
 67→  }
 68→
 69→  return {
 70→    group,
 71→
 72→    /**
 73→     * Update the grid to display on the given drawing plane.
 74→     * @param {Object} plane - Drawing plane with origin, normal, uAxis, vAxis
 75→     * @param {number} gridSize - Grid spacing in mm (default 50)
 76→     * @param {number} extent - Grid extent in mm (default 2000)
 77→     */
 78→    setPlane(plane, gridSize = 50, extent = 2000) {
 79→      clearGrid();
 80→
 81→      const gridGroup = new THREE.Group();
 82→      gridGroup.name = 'PlaneGrid';
 83→
 84→      // Create grid lines
 85→      const halfExtent = extent;
 86→      const lines = [];
 87→      for (let i = -halfExtent; i <= halfExtent; i += gridSize) {
 88→        // Lines along u axis
 89→        lines.push(
 90→          planeToThree(plane, i, -halfExtent),
 91→          planeToThree(plane, i, halfExtent),
 92→        );
 93→        // Lines along v axis
 94→        lines.push(
 95→          planeToThree(plane, -halfExtent, i),
 96→          planeToThree(plane, halfExtent, i),
 97→        );
 98→      }
 99→
100→      if (lines.length > 0) {
101→        const points = lines.map((p) => new THREE.Vector3(p.x, p.y, p.z));
102→        const geometry = new THREE.BufferGeometry().setFromPoints(points);
103→        const lineSegments = new THREE.LineSegments(geometry, gridLineMaterial);
104→        gridGroup.add(lineSegments);
105→      }
106→
107→      gridMesh = gridGroup;
108→      group.add(gridMesh);
109→    },
110→
111→    /**
112→     * Show or update a rectangle preview on the drawing plane.
113→     * @param {Object} plane - Drawing plane
114→     * @param {Object} startLocal - { u, v } start corner in plane-local coords
115→     * @param {Object} endLocal - { u, v } end corner in plane-local coords
116→     */
117→    setPreviewRect(plane, startLocal, endLocal) {
118→      clearPreview();
119→
120→      if (!startLocal || !endLocal) return;
121→
122→      const u1 = Math.min(startLocal.u, endLocal.u);
123→      const v1 = Math.min(startLocal.v, endLocal.v);
124→      const u2 = Math.max(startLocal.u, endLocal.u);
125→      const v2 = Math.max(startLocal.v, endLocal.v);
126→
127→      const corners = [
128→        planeToThree(plane, u1, v1),
129→        planeToThree(plane, u2, v1),
130→        planeToThree(plane, u2, v2),
131→        planeToThree(plane, u1, v2),
132→      ];
133→
134→      // Fill quad
135→      const quadGeometry = new THREE.BufferGeometry();
136→      const vertices = new Float32Array([
137→        corners[0].x, corners[0].y, corners[0].z,
138→        corners[1].x, corners[1].y, corners[1].z,
139→        corners[2].x, corners[2].y, corners[2].z,
140→        corners[0].x, corners[0].y, corners[0].z,
141→        corners[2].x, corners[2].y, corners[2].z,
142→        corners[3].x, corners[3].y, corners[3].z,
143→      ]);
144→      quadGeometry.setAttribute('position', new THREE.BufferAttribute(vertices, 3));
145→      const quad = new THREE.Mesh(quadGeometry, previewMaterial);
146→
147→      // Edge outline
148→      const edgePoints = [...corners, corners[0]].map((c) => new THREE.Vector3(c.x, c.y, c.z));
149→      const edgeGeometry = new THREE.BufferGeometry().setFromPoints(edgePoints);
150→      const edge = new THREE.Line(edgeGeometry, previewEdgeMaterial);
151→
152→      const previewGroup = new THREE.Group();
153→      previewGroup.name = 'DrawPreview';
154→      previewGroup.add(quad);
155→      previewGroup.add(edge);
156→
157→      previewMesh = previewGroup;
158→      group.add(previewMesh);
159→    },
160→
161→    clearPreview,
162→    clearGrid,
163→
164→    dispose() {
165→      clearGrid();
166→      clearPreview();
167→      gridMaterial.dispose();
168→      gridLineMaterial.dispose();
169→      previewMaterial.dispose();
170→      previewEdgeMaterial.dispose();
171→    },
172→  };
173→}
174→
175→/**
176→ * Convert plane-local (u, v) to Three.js world coordinates.
177→ * Domain: x=x, y=y, z=z -> Three.js: x=x, y=z, z=y
178→ */
179→function planeToThree(plane, u, v) {
180→  const wx = plane.origin.x + u * plane.uAxis.x + v * plane.vAxis.x;
181→  const wy = plane.origin.y + u * plane.uAxis.y + v * plane.vAxis.y;
182→  const wz = plane.origin.z + u * plane.uAxis.z + v * plane.vAxis.z;
183→  // Convert domain coords to Three.js coords
184→  return { x: wx, y: wz, z: wy };
185→}
